import React, { useState, useEffect, useRef } from 'react';
import { useMusic } from '../context/MusicContext';
import { Play, Pause, SkipBack, SkipForward, ListPlus, Heart, Music } from 'lucide-react';
import axios from 'axios';

const GlobalPlayer = () => {
  const { currentSong, isPlaying, togglePlay, handleNext, handlePrev, audioRef, updateCurrentSongLikes } = useMusic();
  const [progress, setProgress] = useState(0);
  const [showMenu, setShowMenu] = useState(false);
  const [userPlaylists, setUserPlaylists] = useState([]);
  const menuRef = useRef(null);
  
  const user = JSON.parse(localStorage.getItem('user'));
  const userId = user?._id || user?.id;

  // Kiểm tra bài hát hiện tại đã được user này Like chưa
  const isLiked = currentSong?.likes?.includes(userId);

  // --- HÀM XỬ LÝ LIKE ---
  const handleToggleLike = async () => {
    if (!userId) return alert("Vui lòng đăng nhập để thích bài hát!");
    try {
      const res = await axios.post(`http://localhost:5000/api/songs/toggle-like`, {
        songId: currentSong._id,
        userId: userId
      });

      // Cập nhật lại danh sách likes trong Context để UI thay đổi ngay lập tức
      let updatedLikes = [...currentSong.likes];
      if (res.data.isLiked) {
        updatedLikes.push(userId);
      } else {
        updatedLikes = updatedLikes.filter(id => id !== userId);
      }
      updateCurrentSongLikes(updatedLikes);

    } catch (err) {
      console.error("Lỗi khi like:", err);
    }
  };

  // --- CÁC LOGIC CŨ ---
  useEffect(() => {
    const handleClickOutside = (e) => {
      if (menuRef.current && !menuRef.current.contains(e.target)) setShowMenu(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const onTimeUpdate = () => {
    const current = audioRef.current.currentTime;
    const total = audioRef.current.duration;
    setProgress((current / total) * 100 || 0);
  };

  const handleSeek = (e) => {
    const seekTime = (e.target.value / 100) * audioRef.current.duration;
    audioRef.current.currentTime = seekTime;
    setProgress(e.target.value);
  };

  if (!currentSong) return null;

  return (
    <div style={playerContainer}>
      {/* 1. Thông tin bài hát & Nút Like */}
      <div style={infoSection}>
        <img src={`http://localhost:5000${currentSong.imageUrl}`} style={playerImg} alt="" />
        <div style={{ overflow: 'hidden', marginRight: '15px' }}>
          <div style={songTitle}>{currentSong.title}</div>
          <div style={songArtist}>{currentSong.artist}</div>
        </div>
        
        {/* NÚT LIKE TRÊN PLAYER */}
        <button onClick={handleToggleLike} style={likeBtnStyle}>
          <Heart 
            size={20} 
            fill={isLiked ? "#1db954" : "none"} 
            color={isLiked ? "#1db954" : "#b3b3b3"} 
          />
        </button>
      </div>

      {/* 2. Bộ điều khiển chính */}
      <div style={controlsSection}>
        <div style={buttonGroup}>
          <SkipBack size={22} style={iconBtn} onClick={handlePrev} />
          <button onClick={togglePlay} style={mainPlayBtn}>
            {isPlaying ? <Pause size={24} fill="white" /> : <Play size={24} fill="white" style={{marginLeft:4}} />}
          </button>
          <SkipForward size={22} style={iconBtn} onClick={handleNext} />
        </div>
        <div style={progressBarContainer}>
          <input type="range" value={progress} onChange={handleSeek} style={sliderStyle} />
        </div>
      </div>

      {/* 3. Thêm vào playlist */}
      <div style={extraSection} ref={menuRef}>
        <button onClick={() => setShowMenu(!showMenu)} style={addPlaylistBtn}>
          <ListPlus size={18} />
        </button>
        {/* Dropdown playlist (giữ nguyên logic cũ của bạn) */}
      </div>

      <audio 
        ref={audioRef} 
        src={`http://localhost:5000${currentSong.songUrl}`} 
        onTimeUpdate={onTimeUpdate}
        onEnded={handleNext}
      />
    </div>
  );
};

// --- STYLES BỔ SUNG ---
const playerContainer = { position: 'fixed', bottom: 0, left: 0, right: 0, background: '#181818', color: '#fff', padding: '15px 30px', display: 'flex', alignItems: 'center', zIndex: 10000, borderTop: '1px solid #282828' };
const infoSection = { width: '30%', display: 'flex', alignItems: 'center' };
const playerImg = { width: '56px', height: '56px', borderRadius: '4px', marginRight: '12px' };
const songTitle = { fontWeight: '600', fontSize: '14px' };
const songArtist = { fontSize: '12px', color: '#b3b3b3' };
const likeBtnStyle = { background: 'none', border: 'none', cursor: 'pointer', padding: '5px', display: 'flex', alignItems: 'center' };
const controlsSection = { flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center' };
const buttonGroup = { display: 'flex', alignItems: 'center', gap: '20px', marginBottom: '8px' };
const mainPlayBtn = { background: '#fff', border: 'none', width: '35px', height: '35px', borderRadius: '50%', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const progressBarContainer = { width: '100%', maxWidth: '400px' };
const sliderStyle = { width: '100%', accentColor: '#1db954', cursor: 'pointer' };
const extraSection = { width: '30%', display: 'flex', justifyContent: 'flex-end' };
const addPlaylistBtn = { background: 'none', color: '#b3b3b3', border: 'none', cursor: 'pointer' };
const iconBtn = { cursor: 'pointer', color: '#b3b3b3' };

export default GlobalPlayer;
